/* Fix the filter syntax:
   - .blurred: blur by 4px
   - .bright: increase brightness to 150%
   - .grayscale: full grayscale (100%)
   - .shadowed: add a drop-shadow */
.gallery {
  display: flex;
  gap: 16px;
  flex-wrap: wrap;
}
.photo {
  width: 150px;
  height: 150px;
  background: linear-gradient(135deg, #667eea, #764ba2);
  border-radius: 8px;
  overflow: hidden;
}
.photo-inner {
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-weight: bold;
}
.blurred {
  filter: blur(4em); /* wrong unit */
}
.bright {
  filter: brightness(15); /* wrong scale */
}
.grayscale {
  filter: grayscale(1%); /* wrong value */
}
.shadowed {
  filter: box-shadow(4px 4px 8px black); /* wrong function */
}

